import os, json, shutil

print('=== STEP 4/5: Disk & Folder Analysis ===')
print()

results = {}

# 1. All drives
print('[Disk Usage - All Drives]')
drives_info = []
for letter in 'CDEFGHIJ':
    drive = letter + ':\\'
    try:
        total, used, free = shutil.disk_usage(drive)
        pct = round(used / total * 100, 1)
        print('  ', drive, '  Total:', round(total/(1024**3),1), 'GB  |  Used:', round(used/(1024**3),1), 'GB  |  Free:', round(free/(1024**3),1), 'GB  |', pct, '%')
        drives_info.append({'drive': drive, 'total_gb': round(total/(1024**3),1), 'used_gb': round(used/(1024**3),1), 'free_gb': round(free/(1024**3),1), 'pct': pct})
    except:
        pass
results['drives'] = drives_info

# 2. Top folders in user profile
print()
print('[Top 15 Largest Folders in User Profile]')
user_home = os.path.expanduser('~')
folder_sizes = []
try:
    for item in os.listdir(user_home):
        full_path = os.path.join(user_home, item)
        if os.path.isdir(full_path):
            total_size = 0
            try:
                for dirpath, dirnames, filenames in os.walk(full_path):
                    for f in filenames:
                        try:
                            fp = os.path.join(dirpath, f)
                            if os.path.isfile(fp):
                                total_size += os.path.getsize(fp)
                        except:
                            pass
                    # Limit depth to avoid very long scans
                    if len(dirpath.split(os.sep)) - len(user_home.split(os.sep)) > 3:
                        dirnames.clear()
            except:
                pass
            folder_sizes.append((item, total_size))
except Exception as e:
    print('  Error scanning:', e)

folder_sizes.sort(key=lambda x: x[1], reverse=True)
folder_report = []
for name, size in folder_sizes[:15]:
    size_mb = round(size / (1024**2), 1)
    bar = '#' * min(int(size_mb / 100), 30)
    print('  ', name.ljust(30), str(size_mb).rjust(10), 'MB ', bar)
    folder_report.append({'name': name, 'size_mb': size_mb})
results['top_folders'] = folder_report

# 3. Temp folder size
print()
print('[Temp Folders]')
temp_dirs = [os.environ.get('TEMP', ''), os.path.join(os.environ.get('LOCALAPPDATA', ''), 'Temp')]
temp_info = []
for td in temp_dirs:
    if td and os.path.isdir(td):
        total = 0
        count = 0
        try:
            for dp, dn, fns in os.walk(td):
                for fn in fns:
                    try:
                        total += os.path.getsize(os.path.join(dp, fn))
                        count += 1
                    except:
                        pass
        except:
            pass
        mb = round(total / (1024**2), 1)
        print('  ', td[:60], ':', mb, 'MB (', count, 'files)')
        temp_info.append({'path': td, 'size_mb': mb, 'files': count})
results['temp'] = temp_info

# Save
report_dir = os.path.join(user_home, 'agent_reports')
os.makedirs(report_dir, exist_ok=True)
with open(os.path.join(report_dir, 'step4_disk.json'), 'w', encoding='utf-8') as f:
    json.dump(results, f, indent=2, ensure_ascii=False)

print()
print('Report saved to:', os.path.join(report_dir, 'step4_disk.json'))
print('=== STEP 4 COMPLETE ===')
